package com.museumheist.game.input;public final class TouchCommandQueue{public static final int DOWN=1,MOVE=2,UP=3,CANCEL=4;public static final class Command{private int type,pointerId;private float x,y;public int getType(){return type;}public int getPointerId(){return pointerId;}public float getX(){return x;}public float getY(){return y;}private void set(int t,int p,float x,float y){type=t;pointerId=p;this.x=x;this.y=y;}}private final int[]types,ids;private final float[]xs,ys;private int head,size;public TouchCommandQueue(int capacity){int c=Math.max(16,capacity);types=new int[c];ids=new int[c];xs=new float[c];ys=new float[c];}public synchronized void offer(int t,int id,float x,float y){if(size==types.length){head=0;size=0;write(CANCEL,-1,0,0);}write(t,id,x,y);}public synchronized boolean poll(Command c){if(size==0)return false;c.set(types[head],ids[head],xs[head],ys[head]);head=(head+1)%types.length;size--;return true;}public synchronized void clear(){head=0;size=0;}public synchronized int size(){return size;}private void write(int t,int id,float x,float y){int tail=(head+size)%types.length;types[tail]=t;ids[tail]=id;xs[tail]=x;ys[tail]=y;size++;}}
